/* ── Banques (codes PK) ─────────────────────────────────────────── */
IF NOT EXISTS (SELECT 1 FROM Banque WHERE code_banque = 'BMCI')
    INSERT INTO Banque (code_banque, nom, swift_bic, pays, actif, version)
    VALUES ('BMCI', N'BMCI — Banque Mauritanienne pour le Commerce International', N'BMCIMRUM', N'Mauritanie', 1, 0);
IF NOT EXISTS (SELECT 1 FROM Banque WHERE code_banque = 'BNM')
    INSERT INTO Banque (code_banque, nom, swift_bic, pays, actif, version)
    VALUES ('BNM', N'BNM — Banque Nationale de Mauritanie', N'BNMRMRUM', N'Mauritanie', 1, 0);
IF NOT EXISTS (SELECT 1 FROM Banque WHERE code_banque = 'GBM')
    INSERT INTO Banque (code_banque, nom, swift_bic, pays, actif, version)
    VALUES ('GBM', N'GBM — Générale de Banque de Mauritanie', N'GBMMRUM', N'Mauritanie', 1, 0);

/* ── Comptes bancaires (IDs fixes pour FK virements) ───────────── */
IF NOT EXISTS (SELECT 1 FROM CompteBanque WHERE id = 9401)
BEGIN
    SET IDENTITY_INSERT CompteBanque ON;
    INSERT INTO CompteBanque (id, numero_compte, libelle, devise, solde, actif, version, code_banque, code_agence)
    VALUES
        (9401, N'MRU-NKC-BMCI-001', N'Compte trésorerie siège BMCI / NKC', N'MRU', 2500000.0000, 1, 0, 'BMCI', 'NKC'),
        (9402, N'MRU-NDB-BNM-001',  N'Compte exploitation BNM / NDB',       N'MRU', 1800000.0000, 1, 0, 'BNM',  'NDB'),
        (9403, N'MRU-NKC-GBM-001',  N'Compte secondaire GBM / NKC',          N'MRU',  950000.0000, 1, 0, 'GBM',  'NKC');
    SET IDENTITY_INSERT CompteBanque OFF;
END

/* ── Écritures comptables factices (une par opération) ─────────── */
IF NOT EXISTS (SELECT 1 FROM comptabilite WHERE IDCOMPTABILITE = 94001)
BEGIN
    SET IDENTITY_INSERT comptabilite ON;
    INSERT INTO comptabilite (IDCOMPTABILITE, DATEOPERATION, DEBIT, CREDIT, LIBELLE, REFERENCE, agence, ETAT, CODE_SENS, VERSION, planComptable)
    VALUES
        (94001, '2026-05-09', 0, 0, N'Virement salaire membre', N'VIR-2026-001', N'NKC', N'VALIDE', N'D', 0, N'512000'),
        (94002, '2026-05-09', 0, 0, N'Provisionnement caisse agence', N'RET-2026-001', N'NDB', N'VALIDE', N'D', 0, N'512000'),
        (94003, '2026-05-09', 0, 0, N'Remise de chèque — encaissement BMCI', N'CHQ-88291', N'NKC', N'VALIDE', N'D', 0, N'512000'),
        (94004, '2026-05-09', 0, 0, N'Virement interne trésorerie — consolidation MRU', N'VIR-2026-002', N'NKC', N'VALIDE', N'D', 0, N'512000'),
        (94005, '2026-05-09', 0, 0, N'Retrait espèces — dotation petite caisse', N'RET-2026-002', N'NDB', N'VALIDE', N'D', 0, N'512000'),
        (94006, '2026-05-09', 0, 0, N'Remise chèques clientèle — lot BNM', N'CHQ-2026-104', N'NDB', N'VALIDE', N'D', 0, N'512000'),
        (94007, '2026-05-09', 0, 0, N'Compensation interbanques — lot MRU', N'VIR-2026-003', N'NKC', N'VALIDE', N'D', 0, N'512000'),
        (94008, '2026-05-09', 0, 0, N'Paiement fournisseur — retrait programmé', N'RET-2026-003', N'NKC', N'VALIDE', N'D', 0, N'512000'),
        (94009, '2026-05-09', 0, 0, N'Encaissement lot chèques présentés GBM', N'CHQ-2026-305', N'NDB', N'VALIDE', N'D', 0, N'512000'),
        (94010, '2026-05-09', 0, 0, N'Approvisionnement compte GBM depuis BMCI', N'VIR-2026-004', N'NKC', N'VALIDE', N'D', 0, N'512000');
    SET IDENTITY_INSERT comptabilite OFF;
END

/* ── 10 opérations : 70% EN_ATTENTE (7), 30% VALIDE (3)
      Indices 1-based : VALIDE aux positions 4, 9, 10 ───────────── */
DECLARE @d DATE = '2026-05-09';

/* 1 — Virement EN_ATTENTE */
IF NOT EXISTS (SELECT 1 FROM OperationBanque WHERE idcomptabilite = 94001 AND dtype = N'Virement')
BEGIN
    INSERT INTO OperationBanque (dtype, date_operation, montant, statut, utilisateur, version, compte_banque_id, code_agence, idcomptabilite)
    VALUES (N'Virement', @d, 50000.0000, N'EN_ATTENTE', N'admin', 0, 9401, N'NKC', 94001);
    INSERT INTO Virement (id, compte_source_id, compte_destination_id, type_virement, reference_externe, motif)
    VALUES (SCOPE_IDENTITY(), 9401, 9402, N'INTRA_BANQUE', N'VIR-2026-001', N'Virement salaire membre — MRU');
END

/* 2 — RetraitBanque EN_ATTENTE */
IF NOT EXISTS (SELECT 1 FROM OperationBanque WHERE idcomptabilite = 94002 AND dtype = N'RetraitBanque')
BEGIN
