    VALUES (N'RetraitBanque', @d, 125000.0000, N'EN_ATTENTE', N'admin', 0, 9402, N'NDB', 94002);
    INSERT INTO RetraitBanque (id, motif, mode_paiement)
    VALUES (SCOPE_IDENTITY(), N'Provisionnement caisse agence Nouadhibou', N'VIREMENT');
END

